import React, { useEffect, useState } from 'react';
import axios from 'axios';

const STORE_ID = '36265ff8-1750-4f6f-8ec7-4c6925e77901';
const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;

function Dashboard() {
  const [products, setProducts] = useState([]);
  const [lowStock, setLowStock] = useState([]);

  useEffect(() => {
    fetchProducts();
  }, []);

  const fetchProducts = async () => {
    try {
      const res = await axios.get(`${BACKEND_URL}/products/${STORE_ID}`);
      const allProducts = res.data.products;
      setProducts(allProducts);
      setLowStock(allProducts.filter(p => p.quantity <= p.low_stock_threshold));
    } catch (err) {
      console.error('Error fetching products:', err);
    }
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <h1>Inventory Dashboard</h1>

      {lowStock.length > 0 && (
        <div style={{ background: '#fff3cd', padding: '15px', borderRadius: '8px', marginBottom: '20px' }}>
          <h3 style={{ color: '#856404' }}>Low Stock Alert!</h3>
          {lowStock.map(p => (
            <p key={p.id} style={{ color: '#856404' }}>
              {p.name} — only {p.quantity} left
            </p>
          ))}
        </div>
      )}

      <h2>All Products</h2>
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr style={{ background: '#f0f0f0' }}>
            <th style={{ padding: '10px', textAlign: 'left' }}>Name</th>
            <th style={{ padding: '10px', textAlign: 'left' }}>SKU</th>
            <th style={{ padding: '10px', textAlign: 'left' }}>Quantity</th>
            <th style={{ padding: '10px', textAlign: 'left' }}>Price (KSh)</th>
          </tr>
        </thead>
        <tbody>
          {products.map(p => (
            <tr key={p.id} style={{ borderBottom: '1px solid #ddd' }}>
              <td style={{ padding: '10px' }}>{p.name}</td>
              <td style={{ padding: '10px' }}>{p.sku}</td>
              <td style={{ padding: '10px', color: p.quantity <= p.low_stock_threshold ? 'red' : 'green' }}>
                {p.quantity}
              </td>
              <td style={{ padding: '10px' }}>KSh {p.price}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Dashboard;
